Berikut implementasi class Python untuk manajemen Docker menggunakan Docker SDK. Kode ini dirancang untuk produksi dengan penanganan error yang ketat dan konfigurasi keamanan dasar.

### Prasyarat
Instal library resmi Docker:
```bash
pip install docker
```

### Implementasi Class `DockerManager`

```python
import docker
from docker.errors import APIError, NotFound, ContainerError
from typing import List, Dict, Optional

class DockerManager:
    def __init__(self, base_url: str = None):
        """
        Inisialisasi koneksi ke Docker Daemon.
        Gunakan base_url='tcp://host:port' untuk remote daemon.
        """
        try:
            self.client = docker.DockerClient(base_url=base_url)
            self.api_client = docker.APIClient(base_url=base_url)
        except docker.errors.DockerException as e:
            raise ConnectionError(f"Gagal terhubung ke Docker Daemon: {e}")

    def list_containers(self, all: bool = False) -> List[Dict]:
        """Mengembalikan daftar container dengan detail dasar."""
        try:
            containers = self.client.containers.list(all=all)
            return [
                {
                    "id": c.short_id,
                    "name": c.name,
                    "status": c.status,
                    "image": c.image.tags[0] if c.image.tags else c.image.id
                }
                for c in containers
            ]
        except APIError as e:
            raise RuntimeError(f"Error mengambil daftar container: {e}")

    def create_container(self, image: str, name: str, 
                         command: Optional[str] = None, 
                         security_opt: bool = True,
                         **kwargs) -> str:
        """
        Membuat container baru.
        Jika security_opt=True, menerapkan hardening dasar (read-only rootfs, drop capabilities).
        """
        try:
            config = {
                "image": image,
                "name": name,
                "command": command,
                "detach": True,
            }

            # Hardening Keamanan Dasar
            if security_opt:
                config.update({
                    "read_only": True,
                    "cap_drop": ["ALL"],
                    "security_opt": ["no-new-privileges:true"],
                    "tmpfs": {"/tmp": "rw,noexec,nosuid,size=64m"}
                })

            # Merge kwargs tambahan (ports, volumes, etc.)
            config.update(kwargs)

            container = self.client.containers.create(**config)
            return container.short_id
        except APIError as e:
            raise RuntimeError(f"Gagal membuat container: {e}")

    def start_container(self, container_id: str) -> bool:
        """Menjalankan container yang berhenti."""
        try:
            container = self.client.containers.get(container_id)
            container.start()
            return True
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal memulai container: {e}")

    def stop_container(self, container_id: str, timeout: int = 10) -> bool:
        """Menghentikan container yang berjalan."""
        try:
            container = self.client.containers.get(container_id)
            container.stop(timeout=timeout)
            return True
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghentikan container: {e}")

    def remove_container(self, container_id: str, force: bool = False) -> bool:
        """Menghapus container dari sistem."""
        try:
            container = self.client.containers.get(container_id)
            container.remove(force=force)
            return True
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghapus container: {e}")

    def get_logs(self, container_id: str, tail: int = 100) -> str:
        """Mengambil log container untuk audit/monitoring."""
        try:
            container = self.client.containers.get(container_id)
            return container.logs(tail=tail).decode('utf-8')
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal mengambil log: {e}")

    def exec_command(self, container_id: str, command: str) -> str:
        """
        Menjalankan command di dalam container.
        Gunakan dengan hati-hati untuk tujuan debugging/audit.
        """
        try:
            container = self.client.containers.get(container_id)
            exit_code, output = container.exec_run(command)
            if exit_code != 0:
                raise ContainerError(f"Command gagal dengan exit code {exit_code}")
            return output.decode('utf-8')
        except NotFound:
            raise ValueError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menjalankan command: {e}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        manager = DockerManager()

        # List container running
        print("Container Aktif:", manager.list_containers())

